import functools, time

def timed(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        ms = (time.perf_counter() - start) * 1000
        print(f"{func.__name__}: {ms:.1f}ms")
        return result
    return wrapper

@timed
def slow_sum(n):
    return sum(range(n))

total = slow_sum(10_000_000)
print(total)

